INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('elementary-0c700c30-moex-00598', 'elementary-0c700c30', 'elementary-0c700c30-moex-112-e8c1e471', 'sub-elementary-0c700c30-04', NULL, 'single_choice', '視訊（Video）指的是同步播放的畫面與聲音，最常見的就是電視的影像。由於面板製作技術的進步， 市場上除了有LED的電視，現在也已經有大尺寸的OLED或MiniLED面板的數位電視。我國在2012 年進入數位電視時代，電視畫面的播出、傳送與接收均使用數位系統。請問下列何者不是數位視訊 標準？', '["HDTV", "NTSC", "SDTV", "UHDTV"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:33+00:00", "source_pdf_sha1": "1e9384d08aea", "answer_pdf_sha1": "eb10e6559f68", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "508", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "資料處理大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "統計"}'::jsonb, NULL),
  ('elementary-0c700c30-moex-00599', 'elementary-0c700c30', 'elementary-0c700c30-moex-112-e8c1e471', 'sub-elementary-0c700c30-04', NULL, 'single_choice', '邏輯閘（LogicGate）是用來進行二元邏輯運算與布林函數的數位邏輯電路（通常以兩個輸入訊號， 一個結果訊號為輸出）。請問有關XNOR閘，下列何者正確？', '["運算符號是", "只有兩個輸⨂入訊號均為0的情況，輸出訊號才會是1，其他不同的輸入情況，輸出訊號都是0", "運算符號是", "只有兩個輸⨁入訊號其中一個是1的情況，輸出訊號才會是0，其他不同的輸入情況，其輸出訊號都 是1"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:33+00:00", "source_pdf_sha1": "1e9384d08aea", "answer_pdf_sha1": "eb10e6559f68", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "508", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "資料處理大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "統計"}'::jsonb, NULL),
  ('elementary-0c700c30-moex-00600', 'elementary-0c700c30', 'elementary-0c700c30-moex-112-e8c1e471', 'sub-elementary-0c700c30-04', NULL, 'single_choice', '利用一把會議金鑰（Session Key）使用對稱式密碼機制對所要傳遞的訊息進行加密。另外再利用接 收方的公開金鑰，使用公開金鑰加密演算法將會議金鑰作加密與密文同時傳給接收方。這種機制稱 之為：', '["數位簽章", "數位金鑰", "數位信封", "數位稽核"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:33+00:00", "source_pdf_sha1": "1e9384d08aea", "answer_pdf_sha1": "eb10e6559f68", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "508", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "資料處理大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "統計"}'::jsonb, NULL),
  ('elementary-0c700c30-moex-00601', 'elementary-0c700c30', 'elementary-0c700c30-moex-112-e8c1e471', 'sub-elementary-0c700c30-04', NULL, 'single_choice', '由於手機、平板電腦的普及，網路的頻寬也大幅的改善。電子商務也進步到所謂的行動商務。消費 者可以由行動終端設備透過無線通訊的方式，進行線上購物、訂票、金融付款或行動銀行等商業行 為。而相關的國際行動支付也非常的普及（如ApplePay、GooglePay）。這些國際行動支付裝在手 機上，手機若有提供一項特別功能，就可以讓裝置進行非接觸式點對點資料傳輸。例如將手機靠近 相關感應裝置，不需要實際的接觸，即可完成刷卡付款的動作。請問這項功能是什麼？', '["藍芽（Bluetooth）", "近場通訊（NFCNearFieldCommunication）", "紅外線傳輸（infraredcommunication）", "無線網路（Wi-Fi）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:33+00:00", "source_pdf_sha1": "1e9384d08aea", "answer_pdf_sha1": "eb10e6559f68", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "508", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "資料處理大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "統計"}'::jsonb, NULL),
  ('elementary-0c700c30-moex-00602', 'elementary-0c700c30', 'elementary-0c700c30-moex-112-e8c1e471', 'sub-elementary-0c700c30-04', NULL, 'single_choice', '電子商務/行動商務越來越普及，許多銀行實體的交易，如轉帳或匯款，很多也可以在網路上進行。 線上銀行為了防止詐騙橫行，也提出許多的方法來防止。其中有一種是由臺灣網路認證公司（TWCA） 所簽發，使用於銀行、證券、保險等金融領域之電子憑證。通常適用於大量、大筆金額的金融交易， 一般企業往來的金融交易或員工薪資匯款，都會使用這種憑證來進行交易，這樣的方法也可使用於 查詢下載所得資料及進行網路報稅作業。請問這種方法是什麼？', '["電子安全交易SET（SecureElectronicTransactions）", "電子晶片卡交易", "自然人憑證", "金融XML憑證（FinancialeXtensibleMarkupLanguage）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:33+00:00", "source_pdf_sha1": "1e9384d08aea", "answer_pdf_sha1": "eb10e6559f68", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "508", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "資料處理大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 42, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "統計"}'::jsonb, NULL),
  ('elementary-0c700c30-moex-00603', 'elementary-0c700c30', 'elementary-0c700c30-moex-112-e8c1e471', 'sub-elementary-0c700c30-04', NULL, 'single_choice', '因為陣列的資料在記憶體存放的位置是連續的，所以若是知道陣列第一個元素的位址及該陣列每一 個元素資料儲存位址的大小（占幾個 byte），就可以根據排放的方式，算出某一個特定元素在記憶 體中的位址。假設有一個三維陣列A[-3:5,-4:2,1:5]，且其起始位置為A[-3,-4,1]=100，陣列每一元 素占記憶體大小2bytes，以列為主排列（RowMajor），請計算A[1,1,3]所在的位置？', '["1345", "2826", "267", "434"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:33+00:00", "source_pdf_sha1": "1e9384d08aea", "answer_pdf_sha1": "eb10e6559f68", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "508", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "資料處理大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "統計"}'::jsonb, NULL),
  ('elementary-0c700c30-moex-00604', 'elementary-0c700c30', 'elementary-0c700c30-moex-112-e8c1e471', 'sub-elementary-0c700c30-04', NULL, 'single_choice', '有一種矩陣（Matrix）稱為上三角或是下三角矩陣，裡面每一個元素可用a (i=1..n, j=1..n)表示。因 i,j 為這種 2 維的矩陣，在對角線以上或以下的元素都是零（考題沒有暗示上三角或下三角到底是對角 線以上或以下是零）。若有一個下三角矩陣，如果零的元素不想浪費記憶體的位置來儲存，我們可 以用一個一維的陣列來儲存這些非零的元素，也就是D[1: n(n+1)/2]=[a , …, a ]。若n=6，且是以 1,1 n,n 列為主（RowMajor）的排列方式，請問D[14]=？', '["a", "a", "a", "a 5,4 6,2 4,2 6,5"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:33+00:00", "source_pdf_sha1": "1e9384d08aea", "answer_pdf_sha1": "eb10e6559f68", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "508", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "資料處理大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "統計"}'::jsonb, NULL),
  ('elementary-0c700c30-moex-00605', 'elementary-0c700c30', 'elementary-0c700c30-moex-112-e8c1e471', 'sub-elementary-0c700c30-04', NULL, 'single_choice', '資料結構的表示法中，運算元及運算子的位置會形成所謂前序或後序的表示法。若有兩個後序表示法， 第一個是10 8 + 6 5 * - 而第二個後序表示法是6 3 5 * - 2 4 - + 2 - 。請問 這兩個後序表示法若用堆疊法運算後，將個別的答案加起來，結果是多少？', '["-30", "-25", "27", "-8"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:33+00:00", "source_pdf_sha1": "1e9384d08aea", "answer_pdf_sha1": "eb10e6559f68", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "508", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "資料處理大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "統計"}'::jsonb, NULL),
  ('elementary-0c700c30-moex-00606', 'elementary-0c700c30', 'elementary-0c700c30-moex-112-e8c1e471', 'sub-elementary-0c700c30-04', NULL, 'single_choice', '二元樹的走訪有前序追蹤（Pre-order）、中序追蹤（In-order）及後序追蹤（Post-order）三種。下列 的二元樹，請問若用前序追蹤結果其第三個輸出的節點，中序追蹤結果其第五個輸出的節點，及後 序追蹤結果其第八個輸出的節點，各分別是什麼？', '["(B,E,G)", "(D,A,C)", "(H,F,G)", "(H,E,G)"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:33+00:00", "source_pdf_sha1": "1e9384d08aea", "answer_pdf_sha1": "eb10e6559f68", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "508", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "資料處理大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 46, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "統計"}'::jsonb, NULL),
  ('elementary-0c700c30-moex-00607', 'elementary-0c700c30', 'elementary-0c700c30-moex-112-e8c1e471', 'sub-elementary-0c700c30-04', NULL, 'single_choice', '一個有n個節點的二元樹，共有2n個Link，但實際上有很多鏈結（Link）是浪費掉。為了改善這個 問題，就有引線二元樹（Thread Binary Tree）的出現。每一個節點都會有左引線跟右引線分別指到 其他合適的節點，並且有額外的欄位來辨識是引線還是正常的指標。若把下圖二元樹的引線畫出來， 請問節點I的右引線及節點G的左引線分別指到那個節點？', '["節點E跟節點F", "節點B跟節點F", "節點B跟節點C", "節點E跟節點C"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:33+00:00", "source_pdf_sha1": "1e9384d08aea", "answer_pdf_sha1": "eb10e6559f68", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "508", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "資料處理大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 47, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "統計"}'::jsonb, NULL)
